#ifndef LIBLEX_H
#define LIBLEX_H

#include <stddef.h>
#include <stdint.h>

#ifdef __cplusplus
extern "C" {
#endif

// Required allocation size of the engine state, in bytes.
extern const size_t lex_state_size;

// Required allocation alignment of the engine state, in bytes.
extern const size_t lex_state_alignment;

// Initialize a state buffer. The buffer must be at least `lex_state_size`
// bytes and aligned to `lex_state_alignment`.
void lex_state_init(void *state);

// Feed one ASCII alphabetic character (a-zA-Z) into the engine.
void lex_add(void *state, uint8_t c);

// Apply a single backspace to the engine state.
void lex_backspace(void *state);

#ifdef __cplusplus
}
#endif

#endif // LIBLEX_H

#include "liblex.h"

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    // aligned_alloc requires size be a multiple of alignment.
    size_t size = ((lex_state_size + lex_state_alignment - 1) /
                   lex_state_alignment) *
                  lex_state_alignment;

    void *state = aligned_alloc(lex_state_alignment, size);
    if (!state) {
        return 1;
    }

    lex_state_init(state);
    lex_add(state, 'a');
    lex_add(state, 'a');
    lex_backspace(state);

    free(state);

    printf("lex_state_size=%zu lex_state_alignment=%zu OK\n",
           lex_state_size, lex_state_alignment);
    return 0;
}

